import 'package:flutter_test/flutter_test.dart';
import 'package:mockito/annotations.dart';
import 'package:mockito/mockito.dart';
import 'package:mon_app/meteo_service.dart';
import 'package:mon_app/affichage_meteo.dart';

// Générer le mock avec build_runner
@GenerateMocks([MeteoService])
import 'mon_test.mocks.dart';

void main() {
  test('afficherTemperature retourne la bonne chaîne', () async {
    // Arrange
    final mockService = MockMeteoService();
    when(mockService.getTemperature()).thenAnswer((_) async => 28.5);

    final affichage = AffichageMeteo(mockService);

    // Act
    final resultat = await affichage.afficherTemperature();

    // Assert
    expect(resultat, 'Température actuelle : 28.5 °C');
    verify(mockService.getTemperature()).called(1);
  });
}
